<template>
  <div class="home">
    <div class="count-number">0{{counter}}.</div>
    <div class="huge-logo">
      <img src="../assets/hugelogo.png" alt="">
    </div>
    <transition @leave="leave">
      <manifestjs v-if="counter == 1"/>
    </transition>
    <transition @leave="leave">
      <animations v-if="counter == 2"/>
    </transition>
    <transition @leave="leave">
      <newsize v-if="counter == 3"/>
    </transition>
    <transition @leave="leave">
      <versions v-if="counter == 4"/>
    </transition>
    <transition @leave="leave">
      <update v-if="counter == 5"/>
    </transition>
    <transition @leave="leave">
      <agents v-if="counter == 6"/>
    </transition>
    <transition @leave="leave">
      <store v-if="counter == 7"/>
    </transition>
    <div class="prev" v-if="counter > 1" @click="count('prev')">
      <span class="text">
        Prev.
      </span>
      <span class="line"></span>
    </div>
    <div class="next" v-if="counter < 7" @click="count('next')">
      <span class="text">
        Next.
      </span>
      <span class="line"></span>
    </div>
  </div>
</template>

<script>
// @ is an alias to /src
import Manifestjs from '@/components/Manifestjs.vue';
import Animations from '@/components/Animations.vue';
import Versions from '@/components/Versions.vue';
import Newsize from '@/components/Newsize.vue';
import Agents from '@/components/Agents.vue';
import Update from '@/components/UpdateUnit.vue';
import Store from '@/components/Store.vue';
import gsap from 'gsap';

export default {
  name: 'Home',
  data() {
    return {
      counter: 1,
    }
  },
  components: {
    Manifestjs,
    Animations,
    Versions,
    Agents,
    Newsize,
    Update,
    Store
  },
  methods: {
    count(direction) {
      this.counter += direction === 'next' ? 1 : -1;
      console.log(this.counter);
    },
    leave(el, done) {
      gsap.to(el, 0.6, {opacity: 0, onComplete: done});
    }
  }
}
</script>

