  transform-origin: right;
  right: 0;
}

.prev .line {
  transform-origin: left;
  left: 0;
}

.prev {
  left: 200px;
}

.prev:hover .text {
  transform: translateX(100px);
}

.prev:hover .line {
  transform: translateY(-50%) scaleX(1);
}

