<template>
  <div class="main-container">
    <div class="content">
      <h1 ref="title">Animations Boilerplate</h1>
      <p ref="description" class="description"></p>
    </div>
    <div class="squares">
      <span ref="first"></span>
      <span ref="second"></span>
      <span ref="third"></span>
      <span ref="fourth"></span>
      <span ref="fourth"></span>
      <span ref="fourth"></span>
    </div>
  </div>
</template>

<script>
import gsap from 'gsap';
import textCharsAnimationVue from '../mixins/textCharsAnimation.vue';
import textLineAnimationVue from '../mixins/textLineAnimation.vue'
export default {
  name: 'Animations',
  data() {
    return {
      title: '',
      description: "We'd say this is the most fun part. Creating our very\nown library for saving us some lines of code its just\n good AF."
    }
  },
  mixins: [textLineAnimationVue, textCharsAnimationVue],
  mounted() {
    this.breakAllTitles(this.$refs.title, 1);
    this.animateTextLines(this.description, this.$refs.description, 2);
    const timeline = gsap.timeline({delay: 2, repeat: 4, yoyo: true, repeatDelay: 0.5});
    const tweenOne = gsap.from('.squares span', 0.5, {x: '-40px', y: '0', opacity: 0, stagger: 0.2});
    const tweenTwo = gsap.to('.squares span', 0.5, {scale: 0.3, ease: 'back.out',  stagger: { // wrap advanced options in an object
        each: 0.05,
        from: "edges",
        grid: "auto",
        ease: "linear",
        amount: 0.3
      },});
    /* const tweenFour = gsap.from('.squares span', 0.7, {scaleY: 0, stagger: 0.2}); */
    timeline
    .add(tweenOne, '+=0')
    .add(tweenTwo, '+=0')
    /* .add(tweenFour, '+=4.5') */
    .play();
  },
  methods: {
  }
}
</script>

